// Waffles v2 — Trivia question bank.
//
// This is the canonical source of truth for trivia content. The runtime game
// (src/app/state.tsx) adapts these into its lighter `Question` shape.
//
// Authoring rules (enforced by scripts/validate-questions.ts):
//  - Exactly 4 answers per question; `correctIndex` in 0..3.
//  - `id` is unique and kebab-namespaced by category, e.g. "movies-001".
//  - No duplicate question text (normalized, case-insensitive).
//  - Difficulty mix per category targets ~40% easy / 40% medium / 20% hard.
//  - `sourceUrl` is a real, reachable reference. Evergreen facts cite the
//    relevant Wikipedia topic article; volatile facts (crypto, recent sports,
//    etc.) cite the authoritative source used when authoring.

export const CATEGORIES = [
  "Movies",
  "Music",
  "Sports",
  "Geography",
  "Crypto",
  "Tech",
  "History",
  "Science",
  "Pop Culture",
  "Food",
  "Gaming",
  "Literature",
] as const;

export type Category = (typeof CATEGORIES)[number];

export type Difficulty = "easy" | "medium" | "hard";

export type BankQuestion = {
  id: string;
  category: Category;
  difficulty: Difficulty;
  question: string;
  /** Exactly four answer choices. */
  answers: [string, string, string, string];
  /** Index (0–3) into `answers` of the single correct choice. */
  correctIndex: 0 | 1 | 2 | 3;
  /** Real, reachable reference URL for the fact. */
  sourceUrl: string;
  /** Seasonal/themed pack tag. Undefined = evergreen (default app); a value
   *  (e.g. "world-cup") scopes the question to a theme's games. */
  pack?: string;
};

